import requests

def test_rating_field_boundary_valid_range():
    base_url = 'http://localhost:8080'
    headers = {'Authorization': 'Bearer <valid_hr_admin_token>'}
    review_id = 'PR-007'

    for rating_value in [1, 5]:
        payload = {
            'rating': rating_value,
            'reviewerComments': 'Test comment',
            'reviewDate': '2024-01-15'
        }
        response = requests.put(
            f'{base_url}/performance-reviews/{review_id}',
            json=payload,
            headers=headers
        )
        assert response.status_code in [200, 201]
        data = response.json()
        assert data['rating'] == rating_value

import requests

def test_rating_field_outside_valid_range():
    base_url = 'http://localhost:8080'
    headers = {'Authorization': 'Bearer <valid_hr_admin_token>'}
    review_id = 'PR-008'

    for rating_value in [0, 6]:
        payload = {
            'rating': rating_value,
            'reviewerComments': 'Test comment',
            'reviewDate': '2024-01-15'
        }
        response = requests.put(
            f'{base_url}/performance-reviews/{review_id}',
            json=payload,
            headers=headers
        )
        assert response.status_code == 400
        error_data = response.json()
        assert 'rating' in error_data.get('error', '').lower()
